import { useAuthContext } from './features/auth/AuthProvider.js';
import { SignInPage } from './features/auth/SignInPage.js';
import { getAppName, getApiBaseUrl } from './lib/config.js';

function WorkspaceShell({ eyebrow, title, copy, children }: { eyebrow: string; title: string; copy: string; children?: React.ReactNode }) {
  return (
    <main className="app-shell">
      <section className="app-card">
        <p className="app-eyebrow">{eyebrow}</p>
        <h1>{title}</h1>
        <p className="app-copy">{copy}</p>
        {children}
      </section>
    </main>
  );
}

export function App() {
  const auth = useAuthContext();
  const appName = getAppName();
  const apiBaseUrl = getApiBaseUrl();

  if (auth.status === 'loading') {
    return <WorkspaceShell eyebrow="Loading session" title={appName} copy="Restoring your authenticated workspace." />;
  }

  if (auth.status === 'signed-out') {
    return <SignInPage />;
  }

  return (
    <WorkspaceShell eyebrow="Gaian workspace" title={appName} copy={`Signed in as ${auth.user?.name}`}>
      <dl className="app-metadata">
        <div>
          <dt>API base</dt>
          <dd>{apiBaseUrl}</dd>
        </div>
        <div>
          <dt>Session</dt>
          <dd>{auth.sessionPath}</dd>
        </div>
      </dl>
    </WorkspaceShell>
  );
}

