const tableNames = Object.values(schema).map((table) => table.name);

describe('database foundations', () => {
  it('defines the core Ship rebuild tables', () => {
    expect(tableNames).toEqual([
      'users',
      'sessions',
      'documents',
      'document_access',
      'comments',
      'uploads',
      'collaboration_metadata',
    ]);
  });

  it('uses foreign keys and metadata columns for the main relations', () => {
    expect(schema.users.columns.map((column) => column.name)).toEqual([
      'id',
      'email',
      'name',
      'avatar_url',
      'created_at',
      'updated_at',
    ]);
    expect(schema.sessions.columns.find((column) => column.name === 'user_id')?.references?.table).toBe('users');
    expect(schema.documents.columns.find((column) => column.name === 'owner_id')?.references?.table).toBe('users');
    expect(schema.comments.columns.find((column) => column.name === 'document_id')?.references?.table).toBe('documents');
    expect(schema.uploads.columns.find((column) => column.name === 'comment_id')?.references?.table).toBe('comments');
    expect(schema.collaboration_metadata.columns.find((column) => column.name === 'document_id')?.primaryKey).toBe(true);
  });

  it('keeps repository records aligned with the persistence model', () => {
    clearUsers();
    clearSessions();
    clearDocumentAccess();

    seedUser({ id: 'user_1', email: 'Ada@Example.com', name: 'Ada', avatarUrl: null, createdAt: 1, updatedAt: 2 });
