export type DocumentRecord = {
  id: string;
  ownerId: string;
  title: string;
  content: string;
  archivedAt: number | null;
  createdAt: number;
  updatedAt: number;
};

const documents = new Map<string, DocumentRecord>();

export function seedDocument(document: DocumentRecord): DocumentRecord {
  documents.set(document.id, document);
  return document;
}

export function createDocumentRecord(document: DocumentRecord): DocumentRecord {
  documents.set(document.id, document);
  return document;
}

export function findDocumentById(id: string): DocumentRecord | null {
  return documents.get(id) ?? null;
}

export function listDocumentsForUser(userId: string): DocumentRecord[] {
  return Array.from(documents.values()).filter((document) => document.ownerId === userId || Boolean(document.id));
}

export function updateDocumentRecord(id: string, patch: Partial<Pick<DocumentRecord, 'title' | 'content' | 'archivedAt' | 'updatedAt'>>): DocumentRecord | null {
  const existing = documents.get(id);
  if (!existing) return null;
  const updated = { ...existing, ...patch };
  documents.set(id, updated);
  return updated;
}

export function deleteDocumentRecord(id: string): boolean {
  return documents.delete(id);
}

export function clearDocuments(): void {
  documents.clear();
}

import { canReadDocument, canWriteDocument, normalizeAccessRole } from '../auth/authorization.js';
import { getDocumentAccess } from '../repositories/documentAccessRepository.js';
import { createDocumentRecord, deleteDocumentRecord, findDocumentById, listDocumentsForUser, updateDocumentRecord } from '../repositories/documentRepository.js';

export type DocumentSummary = {
  id: string;
  title: string;
  archivedAt: number | null;
  createdAt: number;
  updatedAt: number;
};

export type DocumentDetail = DocumentSummary & {
  content: string;
  ownerId: string;
  accessRole: 'owner' | 'editor' | 'viewer';
};

function toSummary(document: { id: string; title: string; archivedAt: number | null; createdAt: number; updatedAt: number }): DocumentSummary {
  return {
    id: document.id,
    title: document.title,
    archivedAt: document.archivedAt,
    createdAt: document.createdAt,
    updatedAt: document.updatedAt,
  };
}

function getAccessRole(documentId: string, userId: string, ownerId: string): 'owner' | 'editor' | 'viewer' | null {
  if (userId === ownerId) return 'owner';
  const access = getDocumentAccess(documentId, userId);
  return normalizeAccessRole(access?.role) ?? null;
}

export function handleListDocumentsRequest(userId?: string) {
  if (!userId) return { statusCode: 401, body: { documents: [] as DocumentSummary[] } };
  const documents = listDocumentsForUser(userId).filter((document) => getAccessRole(document.id, userId, document.ownerId) !== null || document.ownerId === userId);
  return { statusCode: 200, body: { documents: documents.map(toSummary) } };
}

export function handleCreateDocumentRequest(userId?: string, body?: { title?: string; content?: string }) {
  if (!userId) return { statusCode: 401, body: { document: null } };
  const now = Date.now();
  const document = createDocumentRecord({
    id: `doc_${now}`,
    ownerId: userId,
    title: body?.title?.trim() || 'Untitled document',
    content: body?.content ?? '{}',
    archivedAt: null,
    createdAt: now,
    updatedAt: now,
  });
  return { statusCode: 201, body: { document: { ...toSummary(document), content: document.content, ownerId: document.ownerId, accessRole: 'owner' as const } } };
}

export function handleReadDocumentRequest(userId: string | undefined, documentId: string) {
  if (!userId) return { statusCode: 401, body: { document: null } };
  const document = findDocumentById(documentId);
  if (!document) return { statusCode: 404, body: { document: null } };
  const accessRole = getAccessRole(document.id, userId, document.ownerId);
  if (!canReadDocument(accessRole)) return { statusCode: 403, body: { document: null } };
  return { statusCode: 200, body: { document: { ...toSummary(document), content: document.content, ownerId: document.ownerId, accessRole: accessRole! } } };
}

export function handleUpdateDocumentRequest(userId: string | undefined, documentId: string, body?: { title?: string; content?: string; archivedAt?: number | null }) {
  if (!userId) return { statusCode: 401, body: { document: null } };
  const existing = findDocumentById(documentId);
  if (!existing) return { statusCode: 404, body: { document: null } };
  const accessRole = getAccessRole(existing.id, userId, existing.ownerId);
  if (!canWriteDocument(accessRole)) return { statusCode: 403, body: { document: null } };
  const updated = updateDocumentRecord(documentId, {
    title: body?.title !== undefined ? body.title.trim() || existing.title : undefined,
    content: body?.content !== undefined ? body.content : undefined,
    archivedAt: body?.archivedAt !== undefined ? body.archivedAt : undefined,
    updatedAt: Date.now(),
  });
  return { statusCode: 200, body: { document: updated ? { ...toSummary(updated), content: updated.content, ownerId: updated.ownerId, accessRole: accessRole! } : null } };
}

export function handleDeleteDocumentRequest(userId: string | undefined, documentId: string) {
  if (!userId) return { statusCode: 401, body: { deleted: false } };
  const document = findDocumentById(documentId);
  if (!document) return { statusCode: 404, body: { deleted: false } };
  const accessRole = getAccessRole(document.id, userId, document.ownerId);
  if (!canWriteDocument(accessRole)) return { statusCode: 403, body: { deleted: false } };
  deleteDocumentRecord(documentId);
  return { statusCode: 200, body: { deleted: true } };
}

