export function handleDeleteDocumentRequest(userId: string | undefined, documentId: string) {
  if (!userId) return { statusCode: 401, body: { deleted: false } };
  const document = findDocumentById(documentId);
  if (!document) return { statusCode: 404, body: { deleted: false } };
  const accessRole = getAccessRole(document.id, userId, document.ownerId);
  if (!canWriteDocument(accessRole)) return { statusCode: 403, body: { deleted: false } };
  deleteDocumentRecord(documentId);
  return { statusCode: 200, body: { deleted: true } };
}

function toUploadShape(upload: { id: string; documentId: string | null; commentId: string | null; uploaderId: string; filename: string; mimeType: string; sizeBytes: number; storagePath: string; createdAt: number }) {
  return upload;
}

export function handleListDocumentUploadsRequest(userId: string | undefined, documentId: string) {
  if (!userId) return { statusCode: 401, body: { uploads: [] as ReturnType<typeof toUploadShape>[] } };
  const document = findDocumentById(documentId);
  if (!document) return { statusCode: 404, body: { uploads: [] as ReturnType<typeof toUploadShape>[] } };
  const accessRole = getAccessRole(document.id, userId, document.ownerId);
  if (!canReadDocument(accessRole)) return { statusCode: 403, body: { uploads: [] as ReturnType<typeof toUploadShape>[] } };
  return { statusCode: 200, body: { uploads: listUploadsForDocument(documentId).map(toUploadShape) } };
}

export function handleCreateUploadRequest(userId: string | undefined, body?: { documentId?: string | null; commentId?: string | null; filename?: string; mimeType?: string; sizeBytes?: number; storagePath?: string }) {
  if (!userId) return { statusCode: 401, body: { upload: null } };
  const document = body?.documentId ? findDocumentById(body.documentId) : null;
  if (body?.documentId && !document) return { statusCode: 404, body: { upload: null } };
  const accessRole = document ? getAccessRole(document.id, userId, document.ownerId) : null;
  if (document && !canWriteDocument(accessRole)) return { statusCode: 403, body: { upload: null } };
  const now = Date.now();
  const upload = createUploadRecord({
    id: `upload_${now}`,
    documentId: body?.documentId ?? null,
    commentId: body?.commentId ?? null,
    uploaderId: userId,
    filename: body?.filename?.trim() || 'attachment.bin',
    mimeType: body?.mimeType?.trim() || 'application/octet-stream',
    sizeBytes: Number.isFinite(body?.sizeBytes) ? Number(body?.sizeBytes) : 0,
    storagePath: body?.storagePath?.trim() || `uploads/${now}`,
    createdAt: now,
  });
  return { statusCode: 201, body: { upload } };
}

export function handleListCommentUploadsRequest(userId: string | undefined, commentId: string) {
  if (!userId) return { statusCode: 401, body: { uploads: [] as ReturnType<typeof toUploadShape>[] } };
  return { statusCode: 200, body: { uploads: listUploadsForComment(commentId).map(toUploadShape) } };
}

