import type { ReactNode } from 'react';
import { App } from './App.js';
import { SignInPage } from './features/auth/SignInPage.js';

export type RouteDefinition = {
  path: string;
  label: string;
  element: ReactNode;
};

function GaianWorkspaceEntry() {
  return <App />;
}

export const routeDefinitions: RouteDefinition[] = [
  { path: '/', label: 'App', element: <App /> },
  { path: '/gaian', label: 'Gaian', element: <GaianWorkspaceEntry /> },
  { path: '/sign-in', label: 'Sign in', element: <SignInPage /> },
];

