import { createContext, useContext } from 'react';
import type { AuthState, AuthUser } from './useAuth.js';

export type AuthContextValue = AuthState & {
  signInPath: string;
  signOutPath: string;
  sessionPath: string;
  refreshSession: () => Promise<void>;
  signOut: () => Promise<void>;
  signIn: (credentials: { email: string; password: string }) => Promise<AuthUser>;
};

const defaultAuthContext: AuthContextValue = {
  status: 'loading',
  user: null,
  signInPath: '/api/auth/sign-in',
  signOutPath: '/api/auth/sign-out',
  sessionPath: '/api/session',
  refreshSession: async () => undefined,
  signOut: async () => undefined,
  signIn: async () => {
    throw new Error('AuthProvider is not mounted.');
  },
};

const AuthContext = createContext<AuthContextValue>(defaultAuthContext);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  return <AuthContext.Provider value={defaultAuthContext}>{children}</AuthContext.Provider>;
}

export function useAuthContext(): AuthContextValue {
  return useContext(AuthContext);
}

tool_input.new_string:
import { createContext, useContext } from 'react';
import type { AuthState, AuthUser } from './useAuth.js';
import { authPathDefaults, getAuthPaths } from '../../lib/config.js';

export type AuthContextValue = AuthState & {
  signInPath: string;
  signOutPath: string;
  sessionPath: string;
  refreshSession: () => Promise<void>;
  signOut: () => Promise<void>;
  signIn: (credentials: { email: string; password: string }) => Promise<AuthUser>;
};

const defaultAuthContext: AuthContextValue = {
  status: 'loading',
  user: null,
  ...authPathDefaults,
  refreshSession: async () => undefined,
  signOut: async () => undefined,
  signIn: async () => {
    throw new Error('AuthProvider is not mounted.');
  },
};

const AuthContext = createContext<AuthContextValue>(defaultAuthContext);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const authPaths = getAuthPaths();
  return <AuthContext.Provider value={{ ...defaultAuthContext, ...authPaths }}>{children}</AuthContext.Provider>;
}

export function useAuthContext(): AuthContextValue {
  return useContext(AuthContext);
}

