import { findUserByEmail } from '../repositories/userRepository.js';
import { verifyPassword } from '../auth/password.js';
import { createSessionCookie, createSessionToken, serializeSessionCookie } from '../auth/session.js';
import { createSessionRecord } from '../repositories/sessionRepository.js';

export async function handleSignInRequest(body: { email?: string; password?: string }) {
  const email = body.email?.trim().toLowerCase() ?? '';
  const password = body.password ?? '';
  const user = findUserByEmail(email);

  if (!user || !(await verifyPassword(password, user.passwordHash))) {
    return { statusCode: 401, body: { error: 'Invalid credentials' } };
  }

  const token = createSessionToken();
  createSessionRecord({
    id: token.tokenHash,
    userId: user.id,
    tokenHash: token.tokenHash,
    expiresAt: token.expiresAt,
  });

  return {
    statusCode: 200,
    body: {
      user: { id: user.id, email: user.email, name: user.name },
      cookie: serializeSessionCookie(createSessionCookie(token.token)),
    },
  };
}

export function handleSignOutRequest() {
  return { statusCode: 204, body: {} };
}

