import { describe, expect, it } from 'vitest';
import { App } from './App.js';
import { getAppName, getApiBaseUrl, getAuthPaths } from './lib/config.js';
import { createServerApp } from './server/app.js';
import { getHealthPayload } from './server/routes/health.js';
import { getServerEnv } from './server/env.js';

describe('bootstrap', () => {
  it('exposes the gaian workspace defaults', () => {
    expect(getAppName()).toBe('Gaian Workspace');
    expect(getApiBaseUrl()).toBe('/api');
    expect(getAuthPaths()).toEqual({
      signInPath: '/api/auth/sign-in',
      signOutPath: '/api/auth/sign-out',
      sessionPath: '/api/session',
    });
  });

  it('exports the app shell component', () => {
    expect(App).toBeTypeOf('function');
  });

  it('keeps the server boot and core endpoints working', () => {
    expect(getServerEnv({ PORT: 'not-a-number' }).PORT).toBe(3000);

    const handleRequest = createServerApp();

    const healthResponse = handleRequest({ method: 'GET', url: '/api/health' });
    expect(healthResponse.statusCode).toBe(200);
    expect(healthResponse.headers['content-type']).toBe('application/json');
    expect(JSON.parse(healthResponse.body)).toEqual(getHealthPayload());

    const sessionResponse = handleRequest({ method: 'GET', url: '/api/session' });
    expect(sessionResponse.statusCode).toBe(401);
    expect(JSON.parse(sessionResponse.body)).toEqual({ user: null });

    const signOutResponse = handleRequest({ method: 'POST', url: '/api/auth/sign-out' });
    expect(signOutResponse.statusCode).toBe(204);
