--- src/server/repositories/documentAccessRepository.ts
import type { AccessRole } from '../auth/authorization.js';

export type DocumentAccessRecord = {
  id: string;
  documentId: string;
  userId: string;
  role: AccessRole;
  createdAt: number;
};

const accessEntries = new Map<string, DocumentAccessRecord>();

function key(documentId: string, userId: string): string {
  return `${documentId}:${userId}`;
}

export function upsertDocumentAccess(record: DocumentAccessRecord): DocumentAccessRecord {
  accessEntries.set(key(record.documentId, record.userId), record);
  return record;
}

export function getDocumentAccess(documentId: string, userId: string): DocumentAccessRecord | null {
  return accessEntries.get(key(documentId, userId)) ?? null;
}

export function clearDocumentAccess(): void {
  accessEntries.clear();
}
--- src/server/repositories/sessionRepository.ts
export type SessionRecord = {
  id: string;
  userId: string;
  tokenHash: string;
  expiresAt: number;
  createdAt: number;
  updatedAt: number;
};

const sessions = new Map<string, SessionRecord>();

export function createSessionRecord(session: SessionRecord): SessionRecord {
  sessions.set(session.tokenHash, session);
  return session;
}

export function findSessionByTokenHash(tokenHash: string): SessionRecord | null {
  return sessions.get(tokenHash) ?? null;
}

export function deleteSessionByTokenHash(tokenHash: string): void {
  sessions.delete(tokenHash);
}

export function clearSessions(): void {
  sessions.clear();
}
