import { clearSessionCookie, createSessionCookie, createSessionToken, serializeSessionCookie, hashSessionToken } from '../auth/session.js';
import { findSessionByTokenHash, deleteSessionByTokenHash, createSessionRecord } from '../repositories/sessionRepository.js';
import { findUserByEmail } from '../repositories/userRepository.js';
import { verifyPassword } from '../auth/password.js';

export async function handleSignInRequest(body: { email?: string; password?: string }) {
  const email = body.email?.trim().toLowerCase() ?? '';
  const password = body.password ?? '';
  const user = findUserByEmail(email);

  if (!user || !(await verifyPassword(password, user.passwordHash))) {
    return { statusCode: 401, body: { error: 'Invalid credentials' } };
  }

  const token = createSessionToken();
  createSessionRecord({
    id: token.tokenHash,
    userId: user.id,
    tokenHash: token.tokenHash,
    expiresAt: token.expiresAt,
    createdAt: Date.now(),
    updatedAt: Date.now(),
  });

  return {
    statusCode: 200,
    body: {
      user: { id: user.id, email: user.email, name: user.name },
      cookie: serializeSessionCookie(createSessionCookie(token.token)),
    },
  };
}

export function handleSignOutRequest(cookieValue?: string) {
  if (cookieValue) {
    deleteSessionByTokenHash(hashSessionToken(cookieValue));
  }

  return { statusCode: 204, body: { cookie: clearSessionCookie() } };
}

export function restoreSessionFromCookie(cookieValue?: string) {
  if (!cookieValue) return null;
  const session = findSessionByTokenHash(hashSessionToken(cookieValue));
  if (!session || session.expiresAt <= Date.now()) return null;
  return session;
}

