type DocumentSummary = {
  id: string;
  title: string;
  updatedAt: string;
  bodyPreview: string;
};

const seedDocuments: DocumentSummary[] = [
  {
    id: 'doc-project-brief',
    title: 'Project brief',
    updatedAt: 'Updated 5 minutes ago',
    bodyPreview: 'Track scope, notes, and the latest delivery plan for the workspace.',
  },
  {
    id: 'doc-launch-checklist',
    title: 'Launch checklist',
    updatedAt: 'Updated yesterday',
    bodyPreview: 'Keep launch blockers, approvals, and release steps in one place.',
  },
];

function LoadingState() {
  return (
    <section className="workspace-panel workspace-panel--centered" aria-live="polite">
      <p className="workspace-eyebrow">Loading workspace</p>
      <h1>Restoring your documents</h1>
      <p className="workspace-copy">Fetching your recent files and access state.</p>
    </section>
  );
}

function DocumentWorkspace({ userName }: { userName: string }) {
  const [documents, setDocuments] = useState<DocumentSummary[]>(seedDocuments);
  const [selectedDocumentId, setSelectedDocumentId] = useState(documents[0]?.id ?? '');
  const [statusMessage, setStatusMessage] = useState('Ready to create or open a document.');
  const selectedDocument = useMemo(
    () => documents.find((document) => document.id === selectedDocumentId) ?? null,
    [documents, selectedDocumentId],
  );

  const handleCreateDocument = () => {
    const nextIndex = documents.length + 1;
    const document: DocumentSummary = {
      id: `doc-${nextIndex}`,
      title: `Untitled document ${nextIndex}`,
      updatedAt: 'Just now',
      bodyPreview: 'Start writing here.',
    };
    setDocuments((current) => [document, ...current]);
    setSelectedDocumentId(document.id);
    setStatusMessage(`Created ${document.title}.`);
  };

  return (
    <main className="workspace-shell">
      <header className="workspace-topbar">
        <div>
          <p className="workspace-eyebrow">Document workspace</p>
          <h1>{getAppName()}</h1>
        </div>
        <div className="workspace-topbar-meta">
          <span>Signed in as {userName}</span>
          <button type="button" onClick={handleCreateDocument}>
            New document
          </button>
        </div>
      </header>

      <section className="workspace-layout">
        <aside className="workspace-sidebar" aria-label="Documents">
          <div className="workspace-sidebar-header">
            <h2>Documents</h2>
            <p>{documents.length} available</p>
          </div>
          {documents.length === 0 ? (
            <div className="workspace-empty-state">
              <h3>No documents yet</h3>
              <p>Create your first document to get started.</p>
              <button type="button" onClick={handleCreateDocument}>
                Create document
              </button>
            </div>
          ) : (
            <ul className="workspace-document-list">
              {documents.map((document) => (
                <li key={document.id}>
                  <button
                    type="button"
                    className={document.id === selectedDocumentId ? 'workspace-document-card is-active' : 'workspace-document-card'}
                    onClick={() => {
                      setSelectedDocumentId(document.id);
                      setStatusMessage(`Opened ${document.title}.`);
                    }}
                  >
                    <strong>{document.title}</strong>
                    <span>{document.updatedAt}</span>
                    <p>{document.bodyPreview}</p>
                  </button>
                </li>
              ))}
            </ul>
          )}
        </aside>

        <section className="workspace-editor" aria-label="Selected document">
          {selectedDocument ? (
            <>
              <div className="workspace-editor-header">
                <div>
                  <p className="workspace-eyebrow">Open document</p>
                  <h2>{selectedDocument.title}</h2>
                </div>
                <span>{selectedDocument.updatedAt}</span>
              </div>
              <label className="workspace-field">
                <span>Title</span>
                <input type="text" value={selectedDocument.title} readOnly />
              </label>
              <label className="workspace-field workspace-field--grow">
                <span>Content</span>
                <textarea value={selectedDocument.bodyPreview} readOnly rows={10} />
              </label>
            </>
          ) : (
            <div className="workspace-empty-state workspace-empty-state--detail">
              <h2>Select a document</h2>
              <p>Open a file from the list or create a new one to begin.</p>
            </div>
          )}
          <p className="workspace-status" role="status">
            {statusMessage}
          </p>
        </section>
      </section>
    </main>
  );
}

function WorkspaceErrorState() {
  return (
    <main className="workspace-shell">
      <section className="workspace-panel workspace-panel--centered">
        <p className="workspace-eyebrow">Workspace unavailable</p>
        <h1>Something went wrong</h1>
        <p className="workspace-copy">We could not load the document workspace.</p>
      </section>
    </main>
  );
}

export function App() {
  const auth = useAuthContext();

  if (auth.status === 'loading') {
    return <LoadingState />;
  }

  if (auth.status === 'signed-out') {
    return <SignInPage />;
  }

  if (auth.status === 'error') {
    return <WorkspaceErrorState />;
  }

  return <DocumentWorkspace userName={auth.user?.name ?? 'Workspace user'} />;
}

:root {
  color-scheme: light;
  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  line-height: 1.5;
  font-weight: 400;
  background: #f5f7fb;
  color: #142033;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-width: 320px;
  min-height: 100vh;
  background: linear-gradient(180deg, #f5f7fb 0%, #e7edf7 100%);
}

button,
input,
textarea,
select {
  font: inherit;
}

button {
  cursor: pointer;
}

#app {
  min-height: 100vh;
}

.app-shell,
.workspace-shell {
  min-height: 100vh;
  padding: 1.5rem;
}

.workspace-shell {
  display: grid;
  gap: 1rem;
}

.workspace-panel,
.app-card {
  width: min(100%, 42rem);
  margin: 0 auto;
  background: rgba(255, 255, 255, 0.9);
  border: 1px solid rgba(20, 32, 51, 0.08);
  border-radius: 1.5rem;
  box-shadow: 0 20px 60px rgba(20, 32, 51, 0.08);
  padding: 2rem;
}

.workspace-panel--centered {
  min-height: calc(100vh - 3rem);
  display: grid;
  align-content: center;
}

.workspace-eyebrow,
.app-eyebrow {
  margin: 0 0 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-size: 0.75rem;
  color: #5b6b84;
}

.workspace-panel h1,
.app-card h1,
.workspace-editor h2 {
  margin: 0;
}

.workspace-copy,
.app-copy {
  margin: 1rem 0 0;
  max-width: 34rem;
  color: #3a4a63;
}

.workspace-topbar {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  align-items: center;
  background: rgba(255, 255, 255, 0.9);
  border: 1px solid rgba(20, 32, 51, 0.08);
  border-radius: 1.25rem;
  padding: 1rem 1.25rem;
}

.workspace-topbar-meta {
  display: flex;
  align-items: center;
  gap: 1rem;
  flex-wrap: wrap;
}

.workspace-topbar button,
.workspace-empty-state button {
  border: none;
  border-radius: 999px;
  background: #1f5eff;
  color: white;
  padding: 0.75rem 1rem;
  font-weight: 600;
}

.workspace-layout {
  display: grid;
  grid-template-columns: minmax(18rem, 24rem) minmax(0, 1fr);
  gap: 1rem;
  min-height: 0;
}

.workspace-sidebar,
.workspace-editor {
  background: rgba(255, 255, 255, 0.9);
  border: 1px solid rgba(20, 32, 51, 0.08);
  border-radius: 1.25rem;
  padding: 1.25rem;
}

.workspace-sidebar-header,
.workspace-editor-header {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  align-items: start;
  margin-bottom: 1rem;
}

.workspace-document-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 0.75rem;
}

.workspace-document-card {
  width: 100%;
  text-align: left;
  border: 1px solid rgba(20, 32, 51, 0.08);
  border-radius: 1rem;
  background: #f7f9fc;
  padding: 1rem;
  color: inherit;
}

.workspace-document-card.is-active {
  border-color: #1f5eff;
  box-shadow: inset 0 0 0 1px #1f5eff;
}

.workspace-document-card strong,
.workspace-document-card span,
.workspace-document-card p {
  display: block;
  margin: 0;
}

.workspace-document-card span {
  color: #5b6b84;
  font-size: 0.9rem;
}

.workspace-document-card p {
  margin-top: 0.5rem;
  color: #3a4a63;
}

.workspace-field {
  display: grid;
  gap: 0.5rem;
  margin-top: 1rem;
}

.workspace-field--grow {
  min-height: 100%;
}

.workspace-field input,
.workspace-field textarea {
  width: 100%;
  border: 1px solid rgba(20, 32, 51, 0.12);
  border-radius: 0.875rem;
  padding: 0.875rem 1rem;
  background: #fff;
  color: #142033;
}

.workspace-field textarea {
  resize: vertical;
  min-height: 16rem;
}

.workspace-empty-state {
  border: 1px dashed rgba(20, 32, 51, 0.16);
  border-radius: 1rem;
  padding: 1rem;
  background: #f8fafc;
}

.workspace-empty-state--detail {
  min-height: 24rem;
  display: grid;
  align-content: center;
}

.workspace-status {
  margin: 1rem 0 0;
  color: #5b6b84;
}

@media (max-width: 900px) {
  .workspace-layout,
  .workspace-topbar {
    grid-template-columns: 1fr;
    flex-direction: column;
    align-items: stretch;
  }
}

import { describe, expect, it } from 'vitest';
import { getAppName, getApiBaseUrl } from '../lib/config.js';
import { createServerApp } from '../server/app.js';
import { getHealthPayload } from '../server/routes/health.js';
import { routeDefinitions } from '../routes.js';

describe('phase 0 smoke surface', () => {
  it('keeps the Ship rebuild app name and api base defaults', () => {
    expect(getAppName()).toBe('Ship Rebuild');
    expect(getApiBaseUrl()).toBe('/api');
  });

  it('serves the health endpoint from the server app', () => {
    const handleRequest = createServerApp();
    const response = handleRequest({ method: 'GET', url: '/api/health' });

    expect(response.statusCode).toBe(200);
    expect(response.headers['content-type']).toBe('application/json');
    expect(JSON.parse(response.body)).toEqual(getHealthPayload());
  });

  it('exposes the document workspace and sign-in routes', () => {
    expect(routeDefinitions.map((route) => route.path)).toEqual(['/', '/sign-in']);
    expect(routeDefinitions.map((route) => route.label)).toEqual(['App', 'Sign in']);
  });
});

