import type { AccessRole } from '../auth/authorization.js';

export type DocumentAccessRecord = {
  id: string;
  documentId: string;
  userId: string;
  role: AccessRole;
  createdAt: number;
};

export type CollaborationPresenceRecord = {
  documentId: string;
  userId: string;
  displayName: string;
  cursorPosition: number | null;
  lastSeenAt: number;
};

export type CollaborationSessionRecord = {
  documentId: string;
  channelId: string;
  revision: number;
  lastPersistedRevision: number;
  updatedAt: number;
};

const accessEntries = new Map<string, DocumentAccessRecord>();
const presenceEntries = new Map<string, CollaborationPresenceRecord>();
const collaborationSessions = new Map<string, CollaborationSessionRecord>();

function key(documentId: string, userId: string): string {
  return `${documentId}:${userId}`;
}

export function upsertDocumentAccess(record: DocumentAccessRecord): DocumentAccessRecord {
  accessEntries.set(key(record.documentId, record.userId), record);
  return record;
}

export function getDocumentAccess(documentId: string, userId: string): DocumentAccessRecord | null {
  return accessEntries.get(key(documentId, userId)) ?? null;
}

export function upsertCollaborationPresence(record: CollaborationPresenceRecord): CollaborationPresenceRecord {
  presenceEntries.set(key(record.documentId, record.userId), record);
  return record;
}

export function listCollaborationPresence(documentId: string): CollaborationPresenceRecord[] {
  return Array.from(presenceEntries.values()).filter((record) => record.documentId === documentId);
}

export function clearCollaborationPresence(): void {
  presenceEntries.clear();
}

export function upsertCollaborationSession(record: CollaborationSessionRecord): CollaborationSessionRecord {
  collaborationSessions.set(record.documentId, record);
  return record;
}

export function getCollaborationSession(documentId: string): CollaborationSessionRecord | null {
  return collaborationSessions.get(documentId) ?? null;
}

export function clearCollaborationSessions(): void {
  collaborationSessions.clear();
}

export function clearDocumentAccess(): void {
  accessEntries.clear();
}

export function clearCollaborationState(): void {
  clearDocumentAccess();
  clearCollaborationPresence();
  clearCollaborationSessions();
}

import { getHealthPayload } from './routes/health.js';
import { handleCreateDocumentRequest, handleDeleteDocumentRequest, handleListDocumentsRequest, handleReadDocumentRequest, handleUpdateDocumentRequest } from './routes/documents.js';
import { handleSessionRequest } from './routes/session.js';
import { handleSignOutRequest } from './routes/auth.js';
import { getCollaborationSession, listCollaborationPresence, upsertCollaborationPresence, upsertCollaborationSession } from './repositories/documentAccessRepository.js';
import { canWriteDocument } from './auth/authorization.js';
import { findDocumentById, updateDocumentRecord } from './repositories/documentRepository.js';

export type ServerRequest = {
  method: string;
  url?: string;
  headers?: Record<string, string | undefined>;
  body?: unknown;
};

export type ServerResponse = {
  statusCode: number;
  headers: Record<string, string>;
  body: string;
};

function parseCookieHeader(cookieHeader: string | undefined, name: string): string | undefined {
  if (!cookieHeader) return undefined;
  const cookie = cookieHeader.split(';').map((part) => part.trim()).find((part) => part.startsWith(`${name}=`));
  return cookie ? decodeURIComponent(cookie.slice(name.length + 1)) : undefined;
}

function getUserId(request: ServerRequest): string | undefined {
  return request.headers?.['x-user-id'];
}

export function createServerApp() {
  return function handleRequest(request: ServerRequest): ServerResponse {
    const url = request.url ?? '/';
    const cookieValue = parseCookieHeader(request.headers?.cookie, 'ship_session');

    if (request.method === 'GET' && url === '/api/health') {
      return { statusCode: 200, headers: { 'content-type': 'application/json' }, body: JSON.stringify(getHealthPayload()) };
    }

    if (request.method === 'GET' && url === '/api/session') {
      const result = handleSessionRequest(cookieValue);
      return { statusCode: result.statusCode, headers: { 'content-type': 'application/json' }, body: JSON.stringify(result.body) };
    }

    if (request.method === 'POST' && url === '/api/auth/sign-out') {
      const result = handleSignOutRequest(cookieValue);
      return {
        statusCode: result.statusCode,
        headers: { 'content-type': 'application/json', 'set-cookie': result.body.cookie },
        body: JSON.stringify({}),
      };
    }

    if (request.method === 'GET' && url === '/api/documents') {
      const userId = getUserId(request);
      const result = handleListDocumentsRequest(userId);
      return { statusCode: result.statusCode, headers: { 'content-type': 'application/json' }, body: JSON.stringify(result.body) };
    }

    if (request.method === 'POST' && url === '/api/documents') {
      const userId = getUserId(request);
      const result = handleCreateDocumentRequest(userId, request.body as { title?: string; content?: string } | undefined);
      return { statusCode: result.statusCode, headers: { 'content-type': 'application/json' }, body: JSON.stringify(result.body) };
    }

    const documentMatch = url.match(/^\/api\/documents\/([^/]+)$/);
    if (documentMatch) {
      const documentId = decodeURIComponent(documentMatch[1]);
      const userId = getUserId(request);
      if (request.method === 'GET') {
        const result = handleReadDocumentRequest(userId, documentId);
        return { statusCode: result.statusCode, headers: { 'content-type': 'application/json' }, body: JSON.stringify(result.body) };
      }
      if (request.method === 'PATCH') {
        const result = handleUpdateDocumentRequest(userId, documentId, request.body as { title?: string; content?: string; archivedAt?: number | null } | undefined);
        return { statusCode: result.statusCode, headers: { 'content-type': 'application/json' }, body: JSON.stringify(result.body) };
      }
      if (request.method === 'DELETE') {
        const result = handleDeleteDocumentRequest(userId, documentId);
        return { statusCode: result.statusCode, headers: { 'content-type': 'application/json' }, body: JSON.stringify(result.body) };
      }
    }

    const collaborationMatch = url.match(/^\/api\/documents\/([^/]+)\/collaboration$/);
    if (collaborationMatch && request.method === 'GET') {
      const documentId = decodeURIComponent(collaborationMatch[1]);
      const userId = getUserId(request);
      const document = documentId ? findDocumentById(documentId) : null;
      if (!userId) return { statusCode: 401, headers: { 'content-type': 'application/json' }, body: JSON.stringify({ channel: null, presence: [], canPersist: false }) };
      if (!document) return { statusCode: 404, headers: { 'content-type': 'application/json' }, body: JSON.stringify({ channel: null, presence: [], canPersist: false }) };
      const session = getCollaborationSession(documentId) ?? upsertCollaborationSession({ documentId, channelId: `channel_${documentId}`, revision: 0, lastPersistedRevision: 0, updatedAt: Date.now() });
      const presence = listCollaborationPresence(documentId);
      return {
        statusCode: 200,
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({ channel: session.channelId, revision: session.revision, presence, canPersist: canWriteDocument(userId === document.ownerId ? 'owner' : null) }),
      };
    }

    const presenceMatch = url.match(/^\/api\/documents\/([^/]+)\/presence$/);
    if (presenceMatch && request.method === 'POST') {
      const documentId = decodeURIComponent(presenceMatch[1]);
      const userId = getUserId(request);
      if (!userId) return { statusCode: 401, headers: { 'content-type': 'application/json' }, body: JSON.stringify({ presence: [] }) };
      const current = findDocumentById(documentId);
      if (!current) return { statusCode: 404, headers: { 'content-type': 'application/json' }, body: JSON.stringify({ presence: [] }) };
      upsertCollaborationPresence({
        documentId,
        userId,
        displayName: (request.body as { displayName?: string } | undefined)?.displayName?.trim() || userId,
