export type CommentRecord = {
  id: string;
  documentId: string;
  authorId: string;
  body: string;
  anchor: string | null;
  createdAt: number;
  updatedAt: number;
};

const comments = new Map<string, CommentRecord>();

export function createCommentRecord(comment: CommentRecord): CommentRecord {
  comments.set(comment.id, comment);
  return comment;
}

export function listCommentsForDocument(documentId: string): CommentRecord[] {
  return Array.from(comments.values())
    .filter((comment) => comment.documentId === documentId)
    .sort((left, right) => left.createdAt - right.createdAt);
}

export function findCommentById(id: string): CommentRecord | null {
  return comments.get(id) ?? null;
}

export function updateCommentRecord(id: string, patch: Partial<Pick<CommentRecord, 'body' | 'anchor' | 'updatedAt'>>): CommentRecord | null {
  const existing = comments.get(id);
  if (!existing) return null;
  const updated = { ...existing, ...patch };
  comments.set(id, updated);
  return updated;
}

export function deleteCommentRecord(id: string): boolean {
  return comments.delete(id);
}

export function clearComments(): void {
  comments.clear();
}

import { canReadDocument, canWriteDocument } from '../auth/authorization.js';
import { getDocumentAccess } from '../repositories/documentAccessRepository.js';
import { findDocumentById } from '../repositories/documentRepository.js';
import { createCommentRecord, deleteCommentRecord, findCommentById, listCommentsForDocument, updateCommentRecord } from '../repositories/commentRepository.js';
import { normalizeAccessRole } from '../auth/authorization.js';

function resolveAccessRole(documentId: string, userId: string, ownerId: string) {
  if (userId === ownerId) return 'owner' as const;
  return normalizeAccessRole(getDocumentAccess(documentId, userId)?.role);
}

function canAccessComments(userId: string | undefined, documentId: string) {
  if (!userId) return null;
  const document = findDocumentById(documentId);
  if (!document) return null;
  return resolveAccessRole(documentId, userId, document.ownerId);
}

export function handleListCommentsRequest(userId: string | undefined, documentId: string) {
  const accessRole = canAccessComments(userId, documentId);
  if (!userId) return { statusCode: 401, body: { comments: [] as ReturnType<typeof listCommentsForDocument> } };
  if (!findDocumentById(documentId)) return { statusCode: 404, body: { comments: [] as ReturnType<typeof listCommentsForDocument> } };
  if (!canReadDocument(accessRole)) return { statusCode: 403, body: { comments: [] as ReturnType<typeof listCommentsForDocument> } };
  return { statusCode: 200, body: { comments: listCommentsForDocument(documentId) } };
}

export function handleCreateCommentRequest(userId: string | undefined, documentId: string, body?: { body?: string; anchor?: string | null }) {
  if (!userId) return { statusCode: 401, body: { comment: null } };
  const document = findDocumentById(documentId);
  if (!document) return { statusCode: 404, body: { comment: null } };
  const accessRole = resolveAccessRole(documentId, userId, document.ownerId);
  if (!canWriteDocument(accessRole)) return { statusCode: 403, body: { comment: null } };
  const now = Date.now();
  const comment = createCommentRecord({
    id: `comment_${now}`,
    documentId,
    authorId: userId,
    body: body?.body?.trim() || 'Untitled comment',
    anchor: body?.anchor?.trim() || null,
    createdAt: now,
    updatedAt: now,
  });
  return { statusCode: 201, body: { comment } };
}

export function handleUpdateCommentRequest(userId: string | undefined, commentId: string, body?: { body?: string; anchor?: string | null }) {
  if (!userId) return { statusCode: 401, body: { comment: null } };
  const existing = findCommentById(commentId);
  if (!existing) return { statusCode: 404, body: { comment: null } };
  const document = findDocumentById(existing.documentId);
  if (!document) return { statusCode: 404, body: { comment: null } };
  const accessRole = resolveAccessRole(existing.documentId, userId, document.ownerId);
  if (existing.authorId !== userId && !canWriteDocument(accessRole)) return { statusCode: 403, body: { comment: null } };
  const updated = updateCommentRecord(commentId, {
    body: body?.body !== undefined ? body.body.trim() || existing.body : undefined,
    anchor: body?.anchor !== undefined ? body.anchor?.trim() || null : undefined,
    updatedAt: Date.now(),
  });
  return { statusCode: 200, body: { comment: updated } };
}

export function handleDeleteCommentRequest(userId: string | undefined, commentId: string) {
  if (!userId) return { statusCode: 401, body: { deleted: false } };
  const existing = findCommentById(commentId);
  if (!existing) return { statusCode: 404, body: { deleted: false } };
  const document = findDocumentById(existing.documentId);
  if (!document) return { statusCode: 404, body: { deleted: false } };
  const accessRole = resolveAccessRole(existing.documentId, userId, document.ownerId);
  if (existing.authorId !== userId && !canWriteDocument(accessRole)) return { statusCode: 403, body: { deleted: false } };
  deleteCommentRecord(commentId);
  return { statusCode: 200, body: { deleted: true } };
}

