import { describe, expect, it } from 'vitest';
import { canReadDocument, canWriteDocument, normalizeAccessRole } from '../../server/auth/authorization.js';
import { handleCreateCommentRequest, handleDeleteCommentRequest, handleListCommentsRequest } from '../../server/routes/comments.js';
import { clearDocuments, seedDocument } from '../../server/repositories/documentRepository.js';
import { clearDocumentAccess, upsertDocumentAccess } from '../../server/repositories/documentAccessRepository.js';
import { clearComments } from '../../server/repositories/commentRepository.js';

describe('document authorization primitives', () => {
  it('normalizes access roles', () => {
    expect(normalizeAccessRole('owner')).toBe('owner');
    expect(normalizeAccessRole('editor')).toBe('editor');
    expect(normalizeAccessRole('viewer')).toBe('viewer');
    expect(normalizeAccessRole('invalid')).toBeNull();
  });

  it('allows read access for all configured roles and write access for editors and owners', () => {
    expect(canReadDocument('viewer')).toBe(true);
    expect(canWriteDocument('viewer')).toBe(false);
    expect(canWriteDocument('editor')).toBe(true);
    expect(canWriteDocument('owner')).toBe(true);
  });

  it('allows document participants to read comments and restricts comment writes to editors and owners', () => {
    clearDocuments();
    clearDocumentAccess();
    clearComments();
    seedDocument({ id: 'doc-1', ownerId: 'owner-1', title: 'Doc', content: '{}', archivedAt: null, createdAt: 1, updatedAt: 1 });
    upsertDocumentAccess({ id: 'access-1', documentId: 'doc-1', userId: 'viewer-1', role: 'viewer', createdAt: 1 });
    upsertDocumentAccess({ id: 'access-2', documentId: 'doc-1', userId: 'editor-1', role: 'editor', createdAt: 1 });

    expect(handleListCommentsRequest('viewer-1', 'doc-1').statusCode).toBe(200);
    expect(handleCreateCommentRequest('viewer-1', 'doc-1', { body: 'Hello' }).statusCode).toBe(403);
    expect(handleCreateCommentRequest('editor-1', 'doc-1', { body: 'Hello' }).statusCode).toBe(201);
    expect(handleDeleteCommentRequest('viewer-1', 'comment-does-not-exist').statusCode).toBe(404);
  });
});

