export type UploadRecord = {
  id: string;
  documentId: string | null;
  commentId: string | null;
  uploaderId: string;
  filename: string;
  mimeType: string;
  sizeBytes: number;
  storagePath: string;
  createdAt: number;
};

const uploads = new Map<string, UploadRecord>();

export function createUploadRecord(upload: UploadRecord): UploadRecord {
  uploads.set(upload.id, upload);
  return upload;
}

export function listUploadsForDocument(documentId: string): UploadRecord[] {
  return Array.from(uploads.values())
    .filter((upload) => upload.documentId === documentId)
    .sort((left, right) => left.createdAt - right.createdAt);
}

export function listUploadsForComment(commentId: string): UploadRecord[] {
  return Array.from(uploads.values())
    .filter((upload) => upload.commentId === commentId)
    .sort((left, right) => left.createdAt - right.createdAt);
}

export function findUploadById(id: string): UploadRecord | null {
  return uploads.get(id) ?? null;
}

export function clearUploads(): void {
  uploads.clear();
}

