import { describe, expect, it } from 'vitest';
import { createServerApp } from '../server/app.js';
import { clearDocuments, seedDocument } from '../server/repositories/documentRepository.js';
import { clearComments } from '../server/repositories/commentRepository.js';
import { clearUploads } from '../server/repositories/uploadRepository.js';
import { clearDocumentAccess } from '../server/repositories/documentAccessRepository.js';

describe('upload routes', () => {
  it('authorizes document uploads and returns attachment metadata', () => {
    clearDocuments();
    clearComments();
    clearUploads();
    clearDocumentAccess();
    seedDocument({ id: 'doc-attach', ownerId: 'user-owner', title: 'Attachments', content: '{}', archivedAt: null, createdAt: 1, updatedAt: 1 });

    const handleRequest = createServerApp();

    const unauthorized = handleRequest({
      method: 'POST',
      url: '/api/uploads',
      headers: {},
      body: { documentId: 'doc-attach', filename: 'notes.pdf', mimeType: 'application/pdf', sizeBytes: 1024, storagePath: 'uploads/notes.pdf' },
    });
    expect(unauthorized.statusCode).toBe(401);

    const created = handleRequest({
      method: 'POST',
      url: '/api/uploads',
      headers: { 'x-user-id': 'user-owner' },
      body: { documentId: 'doc-attach', filename: 'notes.pdf', mimeType: 'application/pdf', sizeBytes: 1024, storagePath: 'uploads/notes.pdf' },
    });
    expect(created.statusCode).toBe(201);
    expect(JSON.parse(created.body)).toMatchObject({
      upload: {
        documentId: 'doc-attach',
        filename: 'notes.pdf',
        mimeType: 'application/pdf',
        sizeBytes: 1024,
        storagePath: 'uploads/notes.pdf',
      },
    });

    const listResponse = handleRequest({ method: 'GET', url: '/api/documents/doc-attach/uploads', headers: { 'x-user-id': 'user-owner' } });
    expect(listResponse.statusCode).toBe(200);
    expect(JSON.parse(listResponse.body).uploads).toHaveLength(1);
  });
});

