import { canReadDocument, canWriteDocument, normalizeAccessRole } from '../auth/authorization.js';
import { getDocumentAccess } from '../repositories/documentAccessRepository.js';
import { createDocumentRecord, deleteDocumentRecord, findDocumentById, listDocumentsForUser, updateDocumentRecord } from '../repositories/documentRepository.js';
import { createUploadRecord, listUploadsForDocument, listUploadsForComment } from '../repositories/uploadRepository.js';

export type DocumentSummary = {
  id: string;
  title: string;
  archivedAt: number | null;
  createdAt: number;
  updatedAt: number;
};

export type DocumentDetail = DocumentSummary & {
  content: string;
  ownerId: string;
  accessRole: 'owner' | 'editor' | 'viewer';
};

function toSummary(document: { id: string; title: string; archivedAt: number | null; createdAt: number; updatedAt: number }): DocumentSummary {
  return {
    id: document.id,
    title: document.title,
    archivedAt: document.archivedAt,
    createdAt: document.createdAt,
    updatedAt: document.updatedAt,
  };
}

function getAccessRole(documentId: string, userId: string, ownerId: string): 'owner' | 'editor' | 'viewer' | null {
  if (userId === ownerId) return 'owner';
  const access = getDocumentAccess(documentId, userId);
  return normalizeAccessRole(access?.role) ?? null;
}

export function handleListDocumentsRequest(userId?: string) {
  if (!userId) return { statusCode: 401, body: { documents: [] as DocumentSummary[] } };
  const documents = listDocumentsForUser(userId).filter((document) => getAccessRole(document.id, userId, document.ownerId) !== null || document.ownerId === userId);
  return { statusCode: 200, body: { documents: documents.map(toSummary) } };
}

export function handleCreateDocumentRequest(userId?: string, body?: { title?: string; content?: string }) {
  if (!userId) return { statusCode: 401, body: { document: null } };
  const now = Date.now();
  const document = createDocumentRecord({
    id: `doc_${now}`,
    ownerId: userId,
    title: body?.title?.trim() || 'Untitled document',
    content: body?.content ?? '{}',
    archivedAt: null,
    createdAt: now,
    updatedAt: now,
  });
  return { statusCode: 201, body: { document: { ...toSummary(document), content: document.content, ownerId: document.ownerId, accessRole: 'owner' as const } } };
}

export function handleReadDocumentRequest(userId: string | undefined, documentId: string) {
  if (!userId) return { statusCode: 401, body: { document: null } };
  const document = findDocumentById(documentId);
  if (!document) return { statusCode: 404, body: { document: null } };
  const accessRole = getAccessRole(document.id, userId, document.ownerId);
  if (!canReadDocument(accessRole)) return { statusCode: 403, body: { document: null } };
  return { statusCode: 200, body: { document: { ...toSummary(document), content: document.content, ownerId: document.ownerId, accessRole: accessRole! } } };
}

export function handleUpdateDocumentRequest(userId: string | undefined, documentId: string, body?: { title?: string; content?: string; archivedAt?: number | null }) {
  if (!userId) return { statusCode: 401, body: { document: null } };
  const existing = findDocumentById(documentId);
  if (!existing) return { statusCode: 404, body: { document: null } };
  const accessRole = getAccessRole(existing.id, userId, existing.ownerId);
  if (!canWriteDocument(accessRole)) return { statusCode: 403, body: { document: null } };
  const updated = updateDocumentRecord(documentId, {
    title: body?.title !== undefined ? body.title.trim() || existing.title : undefined,
    content: body?.content !== undefined ? body.content : undefined,
    archivedAt: body?.archivedAt !== undefined ? body.archivedAt : undefined,
    updatedAt: Date.now(),
  });
  return { statusCode: 200, body: { document: updated ? { ...toSummary(updated), content: updated.content, ownerId: updated.ownerId, accessRole: accessRole! } : null } };
}

export function handleDeleteDocumentRequest(userId: string | undefined, documentId: string) {
  if (!userId) return { statusCode: 401, body: { deleted: false } };
  const document = findDocumentById(documentId);
  if (!document) return { statusCode: 404, body: { deleted: false } };
  const accessRole = getAccessRole(document.id, userId, document.ownerId);
  if (!canWriteDocument(accessRole)) return { statusCode: 403, body: { deleted: false } };
  deleteDocumentRecord(documentId);
  return { statusCode: 200, body: { deleted: true } };
}

export function handleListDocumentUploadsRequest(userId: string | undefined, documentId: string) {
  if (!userId) return { statusCode: 401, body: { uploads: [] } };
  const document = findDocumentById(documentId);
  if (!document) return { statusCode: 404, body: { uploads: [] } };
  const accessRole = getAccessRole(document.id, userId, document.ownerId);
  if (!canReadDocument(accessRole)) return { statusCode: 403, body: { uploads: [] } };
  return { statusCode: 200, body: { uploads: listUploadsForDocument(documentId) } };
}

export function handleCreateUploadRequest(userId: string | undefined, body?: { documentId?: string | null; commentId?: string | null; filename?: string; mimeType?: string; sizeBytes?: number; storagePath?: string }) {
  if (!userId) return { statusCode: 401, body: { upload: null } };
  const document = body?.documentId ? findDocumentById(body.documentId) : null;
  if (body?.documentId && !document) return { statusCode: 404, body: { upload: null } };
  const accessRole = document ? getAccessRole(document.id, userId, document.ownerId) : null;
  if (document && !canWriteDocument(accessRole)) return { statusCode: 403, body: { upload: null } };
  const now = Date.now();
  const upload = createUploadRecord({
    id: `upload_${now}`,
    documentId: body?.documentId ?? null,
    commentId: body?.commentId ?? null,
    uploaderId: userId,
    filename: body?.filename?.trim() || 'attachment.bin',
    mimeType: body?.mimeType?.trim() || 'application/octet-stream',
    sizeBytes: Number.isFinite(body?.sizeBytes) ? Number(body?.sizeBytes) : 0,
    storagePath: body?.storagePath?.trim() || `uploads/${now}`,
    createdAt: now,
  });
  return { statusCode: 201, body: { upload } };
}

export function handleListCommentUploadsRequest(userId: string | undefined, commentId: string) {
  if (!userId) return { statusCode: 401, body: { uploads: [] } };
  return { statusCode: 200, body: { uploads: listUploadsForComment(commentId) } };
}

import { useEffect, useMemo, useRef, useState } from 'react';
import { useAuthContext } from './features/auth/AuthProvider.js';
import { SignInPage } from './features/auth/SignInPage.js';
import { getAppName } from './lib/config.js';

type CommentRecord = {
  id: string;
  author: string;
  anchor: string;
  body: string;
  createdAt: string;
  uploads: UploadRecord[];
};

type UploadRecord = {
  id: string;
  filename: string;
  mimeType: string;
  sizeBytes: number;
};

type DocumentRecord = {
  id: string;
  title: string;
  body: string;
  updatedAt: string;
  comments: CommentRecord[];
  uploads: UploadRecord[];
};

const seedDocuments: DocumentRecord[] = [
  {
    id: 'doc-project-brief',
    title: 'Project brief',
    updatedAt: 'Updated 5 minutes ago',
    body: 'Track scope, notes, and the latest delivery plan for the workspace.',
    uploads: [{ id: 'upload-1', filename: 'brief-outline.pdf', mimeType: 'application/pdf', sizeBytes: 182044 }],
    comments: [
      { id: 'comment-1', author: 'Avery', anchor: 'Intro', body: 'Let’s keep this section short and actionable.', createdAt: '10:05 AM', uploads: [] },
      { id: 'comment-2', author: 'Jordan', anchor: 'Delivery plan', body: 'Can we add the dependencies list here?', createdAt: '10:12 AM', uploads: [{ id: 'upload-2', filename: 'dependencies.png', mimeType: 'image/png', sizeBytes: 98444 }] },
    ],
  },
  {
    id: 'doc-launch-checklist',
    title: 'Launch checklist',
    updatedAt: 'Updated yesterday',
    body: 'Keep launch blockers, approvals, and release steps in one place.',
    uploads: [],
    comments: [],
  },
];

const makePreview = (body: string) => body.slice(0, 96) || 'Start writing here.';

function WorkspaceToolbar({ onUpload }: { onUpload: () => void }) {
  return <button type="button" onClick={onUpload}>Attach file</button>;
}

function DocumentWorkspace({ userName }: { userName: string }) {
  const [documents, setDocuments] = useState<DocumentRecord[]>(seedDocuments);
  const [selectedDocumentId, setSelectedDocumentId] = useState(documents[0]?.id ?? '');
  const [statusMessage, setStatusMessage] = useState('Ready to create or open a document.');
  const [commentBody, setCommentBody] = useState('');
  const [commentAnchor, setCommentAnchor] = useState('Selected section');
  const uploadInputRef = useRef<HTMLInputElement | null>(null);

  const selectedDocument = useMemo(() => documents.find((document) => document.id === selectedDocumentId) ?? null, [documents, selectedDocumentId]);

  useEffect(() => {
    if (!selectedDocumentId && documents[0]) setSelectedDocumentId(documents[0].id);
  }, [documents, selectedDocumentId]);

  useEffect(() => {
    setCommentBody('');
    setCommentAnchor('Selected section');
  }, [selectedDocumentId]);

  const updateDocument = (id: string, patch: Partial<DocumentRecord>) => {
    setDocuments((current) => current.map((document) => (document.id === id ? { ...document, ...patch, updatedAt: 'Just now' } : document)));
  };

  const handleCreateDocument = () => {
    const nextIndex = documents.length + 1;
    const document: DocumentRecord = { id: `doc-${nextIndex}`, title: `Untitled document ${nextIndex}`, updatedAt: 'Just now', body: 'Start writing here.', comments: [], uploads: [] };
    setDocuments((current) => [document, ...current]);
    setSelectedDocumentId(document.id);
    setStatusMessage(`Created ${document.title}.`);
  };

  const handleSelectDocument = (document: DocumentRecord) => {
    setSelectedDocumentId(document.id);
    setStatusMessage(`Opened ${document.title}.`);
  };

  const handleAddComment = () => {
    if (!selectedDocument || !commentBody.trim()) return;
    const comment: CommentRecord = { id: `comment-${Date.now()}`, author: userName, anchor: commentAnchor.trim() || 'Selected section', body: commentBody.trim(), createdAt: 'Just now', uploads: [] };
    updateDocument(selectedDocument.id, { comments: [...selectedDocument.comments, comment] });
    setCommentBody('');
    setStatusMessage(`Added a comment to ${selectedDocument.title}.`);
  };

  const handleAttachFile = () => uploadInputRef.current?.click();

  const handleUploadSelected = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file || !selectedDocument) return;
    const upload: UploadRecord = { id: `upload-${Date.now()}`, filename: file.name, mimeType: file.type || 'application/octet-stream', sizeBytes: file.size };
    updateDocument(selectedDocument.id, { uploads: [...selectedDocument.uploads, upload] });
    setStatusMessage(`Attached ${file.name} to ${selectedDocument.title}.`);
    event.target.value = '';
  };

  return (
    <main className="workspace-shell">
      <header className="workspace-topbar">
        <div>
          <p className="workspace-eyebrow">Document workspace</p>
          <h1>{getAppName()}</h1>
        </div>
        <div className="workspace-topbar-meta">
          <span>Signed in as {userName}</span>
          <WorkspaceToolbar onUpload={handleAttachFile} />
          <button type="button" onClick={handleCreateDocument}>New document</button>
          <input ref={uploadInputRef} className="workspace-file-input" type="file" onChange={handleUploadSelected} />
        </div>
      </header>

      <section className="workspace-layout">
        <aside className="workspace-sidebar" aria-label="Documents">
          <div className="workspace-sidebar-header">
            <h2>Documents</h2>
            <p>{documents.length} available</p>
          </div>
          <ul className="workspace-document-list">
            {documents.map((document) => (
              <li key={document.id}>
                <button type="button" className={document.id === selectedDocumentId ? 'workspace-document-card is-active' : 'workspace-document-card'} onClick={() => handleSelectDocument(document)}>
                  <strong>{document.title}</strong>
                  <span>{document.updatedAt}</span>
                  <p>{makePreview(document.body)}</p>
                </button>
              </li>
            ))}
          </ul>
        </aside>

        <section className="workspace-editor" aria-label="Selected document">
          {selectedDocument ? (
            <>
              <div className="workspace-editor-header">
                <div>
                  <p className="workspace-eyebrow">Open document</p>
                  <h2>{selectedDocument.title}</h2>
                </div>
                <span>{selectedDocument.updatedAt}</span>
              </div>
              <label className="workspace-field">
                <span>Title</span>
                <input type="text" value={selectedDocument.title} onChange={(event) => updateDocument(selectedDocument.id, { title: event.target.value })} />
              </label>
              <label className="workspace-field workspace-field--grow">
                <span>Content</span>
                <textarea value={selectedDocument.body} rows={9} onChange={(event) => updateDocument(selectedDocument.id, { body: event.target.value })} />
              </label>

              <section className="workspace-attachments" aria-label="Attachments">
                <div className="workspace-attachments-header">
                  <h3>Files</h3>
                  <span>{selectedDocument.uploads.length} attachments</span>
                </div>
                {selectedDocument.uploads.length ? <ul className="workspace-attachment-list">{selectedDocument.uploads.map((upload) => <li key={upload.id}><span>{upload.filename}</span><small>{upload.mimeType} · {upload.sizeBytes} bytes</small></li>)}</ul> : <p className="workspace-empty-copy">No files attached yet.</p>}
              </section>

              <section className="workspace-comments" aria-label="Comments">
                <div className="workspace-comments-header">
                  <div>
                    <p className="workspace-eyebrow">Contextual discussion</p>
                    <h3>Comments</h3>
                  </div>
                  <span>{selectedDocument.comments.length} threads</span>
                </div>
                <div className="workspace-comment-composer">
                  <label className="workspace-field">
                    <span>Anchor</span>
                    <input type="text" value={commentAnchor} onChange={(event) => setCommentAnchor(event.target.value)} />
                  </label>
                  <label className="workspace-field workspace-field--grow">
                    <span>Comment</span>
                    <textarea value={commentBody} rows={4} onChange={(event) => setCommentBody(event.target.value)} placeholder="Leave feedback for the current section" />
                  </label>
                  <button type="button" onClick={handleAddComment}>Post comment</button>
                </div>
                <ul className="workspace-comment-list">
                  {selectedDocument.comments.map((comment) => (
                    <li key={comment.id} className="workspace-comment-card">
                      <div className="workspace-comment-meta"><strong>{comment.author}</strong><span>{comment.createdAt}</span></div>
                      <p className="workspace-comment-anchor">{comment.anchor}</p>
                      <p>{comment.body}</p>
                      {comment.uploads.length ? <ul className="workspace-mini-attachment-list">{comment.uploads.map((upload) => <li key={upload.id}>{upload.filename}</li>)}</ul> : null}
                    </li>
                  ))}
                </ul>
              </section>
            </>
          ) : (
            <div className="workspace-empty-state workspace-empty-state--detail"><h2>Select a document</h2><p>Open a file from the list or create a new one to begin.</p></div>
          )}
          <p className="workspace-status" role="status">{statusMessage}</p>
        </section>
      </section>
    </main>
  );
}

function WorkspaceErrorState() {
  return <main className="workspace-shell"><section className="workspace-panel workspace-panel--centered"><p className="workspace-eyebrow">Workspace unavailable</p><h1>Something went wrong</h1><p className="workspace-copy">We could not load the document workspace.</p></section></main>;
}

export function App() {
  const auth = useAuthContext();
  if (auth.status === 'loading') return <LoadingState />;
  if (auth.status === 'signed-out') return <SignInPage />;
  return <DocumentWorkspace userName={auth.user?.name ?? 'Workspace user'} />;
}

