import { describe, expect, it } from 'vitest';
import { getAppName, getApiBaseUrl } from '../lib/config.js';
import { routeDefinitions } from '../routes.js';
import { createServerApp } from '../server/app.js';
import { getServerEnv } from '../server/env.js';

describe('phase 9 integrated gate', () => {
  it('keeps the workspace client and route shell aligned', () => {
    expect(getAppName()).toBe('Ship Rebuild');
    expect(getApiBaseUrl()).toBe('/api');
    expect(routeDefinitions.map((route) => route.path)).toEqual(['/', '/sign-in']);
  });

  it('exposes the core api entrypoints through the server app', () => {
    const handleRequest = createServerApp();

    const health = handleRequest({ method: 'GET', url: '/api/health' });
    expect(health.statusCode).toBe(200);

    const missing = handleRequest({ method: 'GET', url: '/api/does-not-exist' });
    expect(missing.statusCode).toBe(404);
  });

  it('normalizes server env defaults for local verification', () => {
    expect(getServerEnv({} as NodeJS.ProcessEnv)).toMatchObject({ NODE_ENV: 'development', PORT: 3000 });
    expect(getServerEnv({ NODE_ENV: 'production', PORT: 'not-a-number' } as NodeJS.ProcessEnv)).toMatchObject({ NODE_ENV: 'production', PORT: 3000 });
  });
});

